module RefModule(
    input clk,
    input reset,
    output reg [3:0] gray
    );

    reg [3:0] obf_count;

    always @(posedge clk) begin
        if (reset) begin
            obf_count <= 4'b0000;
        end else begin
            obf_count <= obf_count + 1;
        end
    end

    always @(obf_count) begin
        gray = (obf_count >> 1) ^ obf_count;
    end
endmodule
